const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  HeadingLevel, AlignmentType, BorderStyle, WidthType, ShadingType,
  LevelFormat, PageNumber, PageBreak, ExternalHyperlink,
  Header, Footer, Tab, TabStopType, TabStopPosition
} = require('docx');
const fs = require('fs');

// ─── Colors ───────────────────────────────────────────────────────────────
const C = {
  deepBlue:  "1A237E",
  blue:      "283593",
  accentBlue:"3949AB",
  lightBlue: "E8EAF6",
  midBlue:   "C5CAE9",
  teal:      "00695C",
  lightTeal: "E0F2F1",
  orange:    "E65100",
  lightOrange:"FFF3E0",
  gray:      "37474F",
  lightGray: "F5F5F5",
  midGray:   "90A4AE",
  white:     "FFFFFF",
  border:    "CFD8DC",
  darkText:  "212121",
  bodyText:  "424242",
};

// ─── Borders ───────────────────────────────────────────────────────────────
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const thinBorder = { style: BorderStyle.SINGLE, size: 1, color: C.border };
const borders = { top: thinBorder, bottom: thinBorder, left: thinBorder, right: thinBorder };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

// ─── Helpers ───────────────────────────────────────────────────────────────
function bold(text, color = C.darkText, size = 22) {
  return new TextRun({ text, bold: true, color, size, font: "Malgun Gothic" });
}
function run(text, color = C.bodyText, size = 20) {
  return new TextRun({ text, color, size, font: "Malgun Gothic" });
}
function code(text) {
  return new TextRun({ text, font: "Courier New", size: 18, color: C.accentBlue, shading: { fill: "EEF0FB" } });
}
function para(children, opts = {}) {
  return new Paragraph({
    children: Array.isArray(children) ? children : [children],
    spacing: { after: opts.afterSpacing ?? 120, before: opts.beforeSpacing ?? 0 },
    indent: opts.indent ? { left: opts.indent } : undefined,
    alignment: opts.align ?? AlignmentType.LEFT,
  });
}
function spacer(pt = 200) {
  return new Paragraph({ children: [], spacing: { after: pt } });
}
function divider(color = C.midBlue) {
  return new Paragraph({
    children: [new TextRun("")],
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color } },
    spacing: { after: 160, before: 160 },
  });
}
function heading1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    children: [new TextRun({ text, bold: true, color: C.deepBlue, size: 32, font: "Malgun Gothic" })],
    spacing: { before: 400, after: 200 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: C.accentBlue, space: 1 } },
  });
}
function heading2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    children: [new TextRun({ text, bold: true, color: C.blue, size: 26, font: "Malgun Gothic" })],
    spacing: { before: 300, after: 160 },
  });
}
function heading3(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_3,
    children: [new TextRun({ text, bold: true, color: C.accentBlue, size: 22, font: "Malgun Gothic" })],
    spacing: { before: 200, after: 100 },
  });
}
function bullet(items) {
  return items.map(item =>
    new Paragraph({
      numbering: { reference: "bullets", level: 0 },
      children: Array.isArray(item) ? item : [run(item)],
      spacing: { after: 80 },
    })
  );
}
function numbered(items) {
  return items.map(item =>
    new Paragraph({
      numbering: { reference: "numbers", level: 0 },
      children: Array.isArray(item) ? item : [run(item)],
      spacing: { after: 80 },
    })
  );
}

// Info box (teal)
function infoBox(title, lines) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [
      new TableRow({ children: [new TableCell({
        borders: { top: { style: BorderStyle.SINGLE, size: 6, color: C.teal }, bottom: thinBorder, left: { style: BorderStyle.SINGLE, size: 12, color: C.teal }, right: thinBorder },
        shading: { fill: C.lightTeal, type: ShadingType.CLEAR },
        margins: { top: 120, bottom: 120, left: 200, right: 160 },
        width: { size: 9360, type: WidthType.DXA },
        children: [
          new Paragraph({ children: [bold("💡 " + title, C.teal, 21)], spacing: { after: 80 } }),
          ...lines.map(l => para([run(l, C.gray, 19)], { afterSpacing: 60 })),
        ],
      })] }),
    ],
  });
}

// Warning box (orange)
function warnBox(title, lines) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [
      new TableRow({ children: [new TableCell({
        borders: { top: { style: BorderStyle.SINGLE, size: 6, color: C.orange }, bottom: thinBorder, left: { style: BorderStyle.SINGLE, size: 12, color: C.orange }, right: thinBorder },
        shading: { fill: C.lightOrange, type: ShadingType.CLEAR },
        margins: { top: 120, bottom: 120, left: 200, right: 160 },
        width: { size: 9360, type: WidthType.DXA },
        children: [
          new Paragraph({ children: [bold("⚠️ " + title, C.orange, 21)], spacing: { after: 80 } }),
          ...lines.map(l => para([run(l, C.gray, 19)], { afterSpacing: 60 })),
        ],
      })] }),
    ],
  });
}

// Code block
function codeBlock(lines) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [
      new TableRow({ children: [new TableCell({
        borders: { top: thinBorder, bottom: thinBorder, left: { style: BorderStyle.SINGLE, size: 8, color: C.accentBlue }, right: thinBorder },
        shading: { fill: "F0F2FA", type: ShadingType.CLEAR },
        margins: { top: 100, bottom: 100, left: 200, right: 160 },
        width: { size: 9360, type: WidthType.DXA },
        children: lines.map(l =>
          new Paragraph({ children: [new TextRun({ text: l, font: "Courier New", size: 18, color: C.accentBlue })], spacing: { after: 40 } })
        ),
      })] }),
    ],
  });
}

// Simple 2-col table
function twoColTable(rows, colWidths = [3000, 6360]) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: colWidths,
    rows: [
      new TableRow({
        children: [
          new TableCell({
            borders, shading: { fill: C.lightBlue, type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 120, right: 120 },
            width: { size: colWidths[0], type: WidthType.DXA },
            children: [new Paragraph({ children: [bold(rows[0][0], C.deepBlue, 19)] })],
          }),
          new TableCell({
            borders, shading: { fill: C.lightBlue, type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 120, right: 120 },
            width: { size: colWidths[1], type: WidthType.DXA },
            children: [new Paragraph({ children: [bold(rows[0][1], C.deepBlue, 19)] })],
          }),
        ],
      }),
      ...rows.slice(1).map((row, i) => new TableRow({
        children: [
          new TableCell({
            borders,
            shading: { fill: i % 2 === 0 ? C.white : C.lightGray, type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 120, right: 120 },
            width: { size: colWidths[0], type: WidthType.DXA },
            children: [new Paragraph({ children: [run(row[0], C.gray, 19)] })],
          }),
          new TableCell({
            borders,
            shading: { fill: i % 2 === 0 ? C.white : C.lightGray, type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 120, right: 120 },
            width: { size: colWidths[1], type: WidthType.DXA },
            children: Array.isArray(row[1])
              ? row[1].map(t => new Paragraph({ children: [typeof t === "string" ? run(t, C.bodyText, 19) : t], spacing: { after: 40 } }))
              : [new Paragraph({ children: [run(row[1], C.bodyText, 19)] })],
          }),
        ],
      })),
    ],
  });
}

// cover page
function coverPage() {
  return [
    new Paragraph({
      children: [],
      spacing: { after: 1200 },
    }),
    new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ text: "🌌  Antigravity IDE", bold: true, size: 48, color: C.deepBlue, font: "Malgun Gothic" })],
      spacing: { after: 160 },
    }),
    new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ text: "+ Awesome Skills", bold: true, size: 40, color: C.accentBlue, font: "Malgun Gothic" })],
      spacing: { after: 300 },
    }),
    new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ text: "실무자를 위한 완전 사용 가이드", size: 28, color: C.gray, font: "Malgun Gothic" })],
      spacing: { after: 160 },
    }),
    new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ text: "LG PRI Production Technology HRD  |  2026.03", size: 22, color: C.midGray, font: "Malgun Gothic" })],
      spacing: { after: 1200 },
    }),
    // version box
    new Table({
      width: { size: 6000, type: WidthType.DXA },
      columnWidths: [1800, 4200],
      rows: [
        new TableRow({ children: [
          new TableCell({ borders, shading: { fill: C.accentBlue, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, width: { size: 1800, type: WidthType.DXA }, children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [bold("버전", C.white, 20)] })] }),
          new TableCell({ borders, shading: { fill: C.lightBlue, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, width: { size: 4200, type: WidthType.DXA }, children: [new Paragraph({ children: [run("v1.20.3 (2026년 3월 기준)", C.bodyText, 20)] })] }),
        ]}),
        new TableRow({ children: [
          new TableCell({ borders, shading: { fill: C.accentBlue, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, width: { size: 1800, type: WidthType.DXA }, children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [bold("스킬 수", C.white, 20)] })] }),
          new TableCell({ borders, shading: { fill: C.lightBlue, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, width: { size: 4200, type: WidthType.DXA }, children: [new Paragraph({ children: [run("233+ (antigravity-awesome-skills)", C.bodyText, 20)] })] }),
        ]}),
        new TableRow({ children: [
          new TableCell({ borders, shading: { fill: C.accentBlue, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, width: { size: 1800, type: WidthType.DXA }, children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [bold("대상", C.white, 20)] })] }),
          new TableCell({ borders, shading: { fill: C.lightBlue, type: ShadingType.CLEAR }, margins: { top: 80, bottom: 80, left: 120, right: 120 }, width: { size: 4200, type: WidthType.DXA }, children: [new Paragraph({ children: [run("Non-developer HR/AX 담당자, Vibe Coder", C.bodyText, 20)] })] }),
        ]}),
      ],
    }),
    new Paragraph({ children: [new PageBreak()], spacing: { after: 0 } }),
  ];
}

// ─── Document ──────────────────────────────────────────────────────────────
const children = [

  // ── COVER ─────────────────────────────────────────────────────────────
  ...coverPage(),

  // ── 1. Antigravity란 무엇인가 ───────────────────────────────────────
  heading1("1. Antigravity란 무엇인가"),

  para([run(
    "Google이 2025년 11월 18일 출시한 Antigravity는 단순한 코드 자동완성 도구가 아닙니다. " +
    "기존의 AI 코딩 어시스턴트(Copilot, Cursor)가 '더 빠른 타이핑을 도와주는 도구'라면, " +
    "Antigravity는 '작업을 위임할 수 있는 AI 직원'에 가깝습니다. " +
    "당신이 '사용자 인증 시스템 만들어줘'라고 말하면, 에이전트가 계획을 세우고, 코드를 작성하고, " +
    "브라우저에서 테스트까지 수행합니다."
  )]),

  spacer(160),

  twoColTable([
    ["구분", "설명"],
    ["출시일", "2025년 11월 18일 (Google DeepMind)"],
    ["현재 버전", "v1.20.3 (2026년 3월 기준), 퍼블릭 프리뷰 — 무료"],
    ["기반 IDE", "VS Code 기반 (확장 설치 불필요, 독립 앱)"],
    ["사용 가능 모델", "Gemini 3.1 Pro (High/Low), Gemini 3 Flash, Claude Sonnet 4.6, Claude Opus 4.6 (Thinking), GPT-OSS 120B"],
    ["핵심 개념", "Agent-first — 에이전트가 편집기·터미널·브라우저를 통합 제어"],
    ["Agent Skills", "SKILL.md 기반 재사용 플레이북 (글로벌/워크스페이스 두 가지 범위)"],
  ]),

  spacer(200),
  infoBox("핵심 차이", [
    "기존 도구: '이 코드 어떻게 고치나요?' → 조언만 제공",
    "Antigravity: '이 버그 고쳐줘' → 직접 파일 수정·테스트·커밋까지 수행",
    "Claude Opus 4.6 (월 $100-200 상당)를 퍼블릭 프리뷰 동안 무료로 사용 가능",
  ]),

  spacer(200),
  heading2("1.1  세 가지 작업 화면 (Three Surfaces)"),

  para([run(
    "Antigravity는 세 개의 영역이 동기화되어 작동합니다. " +
    "Agent Manager에서 작업을 지시하면, 에이전트가 Editor에서 코드를 쓰고, Browser에서 결과를 검증합니다."
  )]),

  spacer(120),
  twoColTable([
    ["화면", "역할 및 특징"],
    ["Agent Manager", "작업 지시 및 진행 상황 모니터링. 여러 에이전트를 병렬로 실행 가능. 기본 시작 화면."],
    ["Editor View", "VS Code와 동일한 편집기 경험. 에이전트가 파일을 직접 수정하는 모습을 실시간으로 확인."],
    ["Browser View", "실제 브라우저로 웹앱 테스트. 에이전트가 클릭·입력·스크린샷 캡처를 자율 수행."],
  ]),

  spacer(200),
  new Paragraph({ children: [new PageBreak()], spacing: { after: 0 } }),

  // ── 2. 설치 & 초기 설정 ────────────────────────────────────────────
  heading1("2. 설치 및 초기 설정"),

  heading2("2.1  Antigravity IDE 설치"),
  ...numbered([
    "https://antigravity.dev 접속 후 OS에 맞는 설치 파일 다운로드",
    "설치 완료 후 Google 계정으로 로그인 (Google AI Pro $20/월 또는 무료 플랜)",
    "처음 실행 시 Agent Manager 화면이 나타남 — 곧바로 한국어로 작업 지시 가능",
  ]),

  spacer(160),
  warnBox("보안 주의사항 (v1.20.3 기준)", [
    "에이전트가 기본적으로 터미널, 파일시스템, 네트워크에 자율 접근합니다.",
    "macOS 사용자: Secure Mode 활성화 + macOS Sandbox(2026.02.23 추가) 필수 권장",
    "Windows/Linux 사용자: 아직 샌드박스 미지원 — 프로덕션 환경에서 관리자 권한으로 실행 금지",
    "Settings > Terminal Permissions에서 'Auto' 레벨 이상으로 설정할 것",
  ]),

  spacer(200),
  heading2("2.2  Awesome Skills 설치 (핵심 확장)"),

  para([run(
    "Antigravity의 진짜 힘은 'Agent Skills'에 있습니다. " +
    "아래 명령 한 줄로 233개 검증된 스킬을 글로벌로 설치합니다."
  )]),

  spacer(120),
  codeBlock([
    "# Antigravity 글로벌 설치 (권장 — 모든 프로젝트에서 사용 가능)",
    "npx antigravity-awesome-skills",
    "",
    "# 설치 경로: ~/.gemini/antigravity/skills/",
    "",
    "# 워크스페이스 전용 설치 (프로젝트별로 관리하고 싶을 때)",
    "npx antigravity-awesome-skills --path .agent/skills",
    "",
    "# 수동 설치 (npm 없을 때)",
    "git clone https://github.com/sickn33/antigravity-awesome-skills.git .agent/skills",
  ]),

  spacer(160),
  infoBox("설치 경로 정리", [
    "글로벌: ~/.gemini/antigravity/skills/  →  모든 프로젝트에서 스킬 사용 가능",
    "워크스페이스: .agent/skills/  →  해당 프로젝트에서만 스킬 사용",
    "두 경로 모두 설치하면 워크스페이스 스킬이 글로벌보다 우선 적용됩니다",
  ]),

  spacer(200),
  heading2("2.3  AGENTS.md 설정 (v1.20.3 신기능)"),

  para([run(
    "v1.20.3부터 Antigravity는 AGENTS.md 파일을 읽어 에이전트 행동 규칙을 설정합니다. " +
    "프로젝트 루트에 아래 파일을 만들면 에이전트가 자동으로 참조합니다."
  )]),

  spacer(120),
  codeBlock([
    "# 프로젝트 루트에 AGENTS.md 생성",
    "# (Claude Code의 CLAUDE.md, Gemini CLI의 GEMINI.md와 동일한 개념)",
    "",
    "# AGENTS.md 예시 내용:",
    "## 언어 규칙",
    "- 모든 코드 주석은 한국어로 작성",
    "- 커밋 메시지 형식: feat/fix/docs: [내용]",
    "",
    "## 프로젝트 컨텍스트",
    "- 이 프로젝트는 Next.js + Supabase 기반 HR 자동화 시스템",
    "- 테스트 없이 PR 금지",
  ]),

  spacer(200),
  new Paragraph({ children: [new PageBreak()], spacing: { after: 0 } }),

  // ── 3. Agent Skills 핵심 사용법 ─────────────────────────────────────
  heading1("3. Agent Skills 핵심 사용법"),

  para([run(
    "Agent Skills는 Antigravity의 핵심 차별점입니다. " +
    "단순히 'AI에게 반복 설명'하는 것에서 '한 번 정의한 전문가 플레이북을 언제나 호출'하는 방식으로 전환됩니다. " +
    "코드로 쓰면, AI가 일반의사에서 전문의로 변신합니다."
  )]),

  spacer(200),
  heading2("3.1  스킬 호출 방법"),

  para([run("Agent Manager 대화창에서 @스킬명 형식으로 호출합니다.")]),
  spacer(120),

  codeBlock([
    "# 기본 호출 형식",
    "@스킬명 [작업 내용]",
    "",
    "# 실제 사용 예시",
    "@brainstorming  HR 자동화 앱의 핵심 기능 5가지 기획해줘",
    "@frontend-design  로그인 페이지 UI 컴포넌트 만들어줘",
    "@systematic-debugging  이 에러 분석하고 수정해줘",
    "@plan-writing  Pulse Check 시스템 구현 계획서 작성해줘",
    "@docx  회의록 Word 문서 생성해줘",
  ]),

  spacer(200),
  heading2("3.2  CSP 업무 추천 스킬 목록"),

  para([bold("① AI 활용도 제고 / Vibe-Coding 교육 관련", C.deepBlue, 21)]),
  spacer(80),

  twoColTable([
    ["스킬명", "용도 및 활용 시나리오"],
    ["@brainstorming", "교육과정 기획, 콘텐츠 아이디어 발산. 창작 작업 전 반드시 먼저 호출 권장"],
    ["@frontend-design", "인터랙티브 HTML 실습 가이드, UI 프로토타입 빠른 생성"],
    ["@plan-writing", "교육 프로그램 설계 문서, 커리큘럼 기획서 작성"],
