{"language": "javascript", "code": "const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  HeadingLevel, AlignmentType, BorderStyle, WidthType, ShadingType,
  LevelFormat, PageNumber, PageBreak, ExternalHyperlink,
  Header, Footer, Tab, TabStopType, TabStopPosition
} = require('docx');
const fs = require('fs');

// ─── Colors ───────────────────────────────────────────────────────────────
const C = {
  deepBlue:  "1A237E",
  blue:      "283593",
  accentBlue:"3949AB",
  lightBlue: "E8EAF6",
  midBlue:   "C5CAE9",
  teal:      "00695C",
  lightTeal: "E0F2F1",
  orange:    "E65100",
  lightOrange:"FFF3E0",
  gray:      "37474F",
  lightGray: "F5F5F5",
  midGray:   "90A4AE",
  white:     "FFFFFF",
  border:    "CFD8DC",
  darkText:  "212121",
  bodyText:  "424242",
};

// ─── Borders ───────────────────────────────────────────────────────────────
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const thinBorder = { style: BorderStyle.SINGLE, size: 1, color: C.border };
const borders = { top: thinBorder, bottom: thinBorder, left: thinBorder, right: thinBorder };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

// ─── Helpers ───────────────────────────────────────────────────────────────
function bold(text, color = C.darkText, size = 22) {
  return new TextRun({ text, bold: true, color, size, font: "Malgun Gothic" });
}
function run(text, color = C.bodyText, size = 20) {
  return new TextRun({ text, color, size, font: "Malgun Gothic" });
}
function code(text) {
  return new TextRun({ text, font: "Courier New", size: 18, color: C.accentBlue, shading: { fill: "EEF0FB" } });
}
function para(children, opts = {}) {
  return new Paragraph({
    children: Array.isArray(children) ? children : [children],
    spacing: { after: opts.afterSpacing ?? 120, before: opts.beforeSpacing ?? 0 },
    indent: opts.indent ? { left: opts.indent } : undefined,
    alignment: opts.align ?? AlignmentType.LEFT,
  });
}
function spacer(pt = 200) {
  return new Paragraph({ children: [], spacing: { after: pt } });
}
function divider(color = C.midBlue) {
  return new Paragraph({
    children: [new TextRun("")],
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color } },
    spacing: { after: 160, before: 160 },
  });
}
function heading1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    children: [new TextRun({ text, bold: true, color: C.deepBlue, size: 32, font: "Malgun Gothic" })],
    spacing: { before: 400, after: 200 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: C.accentBlue, space: 1 } },
  });
}
function heading2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    children: [new TextRun({ text, bold: true, color: C.blue, size: 26, font: "Malgun Gothic" })],
    spacing: { before: 300, after: 160 },
  });
}
function heading3(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_3,
    children: [new TextRun({ text, bold: true, color: C.accentBlue, size: 22, font: "Malgun Gothic" })],
    spacing: { before: 200, after: 100 },
  });
}
function bullet(items) {
  return items.map(item =>
    new Paragraph({
      numbering: { reference: "bullets", level: 0 },
      children: Array.isArray(item) ? item : [run(item)],
      spacing: { after: 80 },
    })
  );
}
function numbered(items) {
  return items.map(item =>
    new Paragraph({
      numbering: { reference: "numbers", level: 0 },
      children: Array.isArray(item) ? item : [run(item)],
      spacing: { after: 80 },
    })
  );
}

// Info box (teal)
function infoBox(title, lines) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [
      new TableRow({ children: [new TableCell({
        borders: { top: { style: BorderStyle.SINGLE, size: 6, color: C.teal }, bottom: thinBorder, left: { style: BorderStyle.SINGLE, size: 12, color: C.teal }, right: thinBorder },
        shading: { fill: C.lightTeal, type: ShadingType.CLEAR },
        margins: { top: 120, bottom: 120, left: 200, right: 160 },
        width: { size: 9360, type: WidthType.DXA },
        children: [
          new Paragraph({ children: [bold("💡 " + title, C.teal, 21)], spacing: { after: 80 } }),
          ...lines.map(l => para([run(l, C.gray, 19)], { afterSpacing: 60 })),
